using Warehouse;

namespace Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker();
    }

    // ─── Stock Level Tests ───────────────────────────────────────────

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-999"));
    }

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-001", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("SKU-001", 30);
        _tracker.AddStock("SKU-001", 20);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void RemoveStock_SufficientStock_DecreasesLevel()
    {
        _tracker.AddStock("SKU-001", 100);
        _tracker.RemoveStock("SKU-001", 40);
        Assert.AreEqual(60, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void RemoveStock_ExactStock_LeavesZero()
    {
        _tracker.AddStock("SKU-001", 25);
        _tracker.RemoveStock("SKU-001", 25);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_ThrowsInvalidOperation()
    {
        _tracker.AddStock("SKU-001", 10);
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-001", 20));
    }

    [TestMethod]
    public void RemoveStock_UnknownSku_ThrowsInvalidOperation()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-NONE", 1));
    }

    // ─── Argument Validation Tests ───────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddStock_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock(sku!, 10));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void AddStock_NonPositiveQuantity_ThrowsArgumentOutOfRange(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-001", qty));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void RemoveStock_NonPositiveQuantity_ThrowsArgumentOutOfRange(int qty)
    {
        _tracker.AddStock("SKU-001", 100);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-001", qty));
    }

    // ─── Reorder Alert Tests ─────────────────────────────────────────

    [TestMethod]
    public void NeedsReorder_NoThresholdSet_ReturnsFalse()
    {
        _tracker.AddStock("SKU-001", 5);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.SetReorderThreshold("SKU-001", 10);
        _tracker.AddStock("SKU-001", 50);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-001", 10);
        _tracker.AddStock("SKU-001", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-001", 10);
        _tracker.AddStock("SKU-001", 3);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_ZeroStockWithThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-001", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void SetReorderThreshold_NegativeValue_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.SetReorderThreshold("SKU-001", -1));
    }

    // ─── Warehouse Transfer Tests ────────────────────────────────────

    [TestMethod]
    public void TransferTo_ValidTransfer_MovesStock()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-001", 100);

        _tracker.TransferTo(destination, "SKU-001", 30);

        Assert.AreEqual(70, _tracker.GetStockLevel("SKU-001"));
        Assert.AreEqual(30, destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_EntireStock_EmptiesSource()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-001", 50);

        _tracker.TransferTo(destination, "SKU-001", 50);

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-001"));
        Assert.AreEqual(50, destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_ThrowsAndDoesNotModifyDestination()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-001", 10);

        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.TransferTo(destination, "SKU-001", 20));

        // Source unchanged, destination untouched
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-001"));
        Assert.AreEqual(0, destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_NullDestination_ThrowsArgumentNull()
    {
        _tracker.AddStock("SKU-001", 10);
        Assert.ThrowsException<ArgumentNullException>(
            () => _tracker.TransferTo(null!, "SKU-001", 5));
    }

    [TestMethod]
    public void TransferTo_DestinationAlreadyHasStock_Accumulates()
    {
        var destination = new InventoryTracker();
        destination.AddStock("SKU-001", 20);
        _tracker.AddStock("SKU-001", 50);

        _tracker.TransferTo(destination, "SKU-001", 15);

        Assert.AreEqual(35, _tracker.GetStockLevel("SKU-001"));
        Assert.AreEqual(35, destination.GetStockLevel("SKU-001"));
    }

    // ─── Integration / Multi-SKU Tests ───────────────────────────────

    [TestMethod]
    public void MultipleSkus_TrackedIndependently()
    {
        _tracker.AddStock("WIDGET", 100);
        _tracker.AddStock("GADGET", 200);
        _tracker.RemoveStock("WIDGET", 10);

        Assert.AreEqual(90, _tracker.GetStockLevel("WIDGET"));
        Assert.AreEqual(200, _tracker.GetStockLevel("GADGET"));
    }

    [TestMethod]
    public void ReorderAlert_TriggeredAfterRemoval()
    {
        _tracker.SetReorderThreshold("SKU-001", 20);
        _tracker.AddStock("SKU-001", 50);

        Assert.IsFalse(_tracker.NeedsReorder("SKU-001"));

        _tracker.RemoveStock("SKU-001", 35);

        Assert.IsTrue(_tracker.NeedsReorder("SKU-001"));
    }
}

